 using System.ComponentModel;
 using System.Net.Http.Json;
 using System.Text.Json;
 using ModelContextProtocol.Server;

 namespace McpServer;

 [McpServerToolType]
 public class ApiTools
 {
     private readonly IHttpClientFactory _httpClientFactory;

     public ApiTools(IHttpClientFactory httpClientFactory)
     {
         _httpClientFactory = httpClientFactory;
     }

     [McpServerTool(Name = "fetch_api"), Description("Fetches JSON data from an external API endpoint.")]
     public async Task<string> FetchApiAsync(
         [Description("The full URL to fetch data from")] string url,
         CancellationToken cancellationToken)
     {
         using var client = _httpClientFactory.CreateClient("api");
         using var response = await client.GetAsync(url, cancellationToken);

         response.EnsureSuccessStatusCode();

         using var doc = await JsonDocument.ParseAsync(
             await response.Content.ReadAsStreamAsync(cancellationToken),
             cancellationToken: cancellationToken);

         return JsonSerializer.Serialize(doc.RootElement, new JsonSerializerOptions { WriteIndented = true });
     }
 }

